import numpy as np

def predict(frame, action):
    out = frame.copy()
    BG = 5
    H, W = out.shape
    CR = 63 if H >= 64 else H - 1  # counter row

    def arm_color(cr, cc):
        for dr, dc in ((0, 1), (0, -1), (1, 0), (-1, 0)):
            r, c = cr + dr, cc + dc
            if 0 <= r < H and 0 <= c < W and out[r, c] != BG and out[r, c] != 0:
                return int(out[r, c])
        return None

    zeros = np.argwhere(out == 0)

    # ---- directional moves: shift the selected cross (the cell == 0) by 3 ----
    if action in (1, 2, 3, 4) and len(zeros) > 0:
        cr, cc = int(zeros[0][0]), int(zeros[0][1])
        C = arm_color(cr, cc)
        if C is not None:
            def arm(dr, dc):
                n, r, c = 0, cr + dr, cc + dc
                while 0 <= r < H and 0 <= c < W and out[r, c] == C:
                    n += 1; r += dr; c += dc
                return n
            up, dn, lf, rt = arm(-1, 0), arm(1, 0), arm(0, -1), arm(0, 1)

            def cells(r0, c0):
                s = {(r0, c0)}
                for i in range(1, up + 1): s.add((r0 - i, c0))
                for i in range(1, dn + 1): s.add((r0 + i, c0))
                for i in range(1, lf + 1): s.add((r0, c0 - i))
                for i in range(1, rt + 1): s.add((r0, c0 + i))
                return s

            d = {1: (-3, 0), 2: (3, 0), 3: (0, -3), 4: (0, 3)}[action]
            ncr, ncc = cr + d[0], cc + d[1]
            old = cells(cr, cc)
            new = cells(ncr, ncc)
            for (r, c) in old - new:
                if 0 <= r < H and 0 <= c < W:
                    out[r, c] = BG
            for (r, c) in new:
                if 0 <= r < H and 0 <= c < W:
                    out[r, c] = C
            if 0 <= ncr < H and 0 <= ncc < W:
                out[ncr, ncc] = 0

        # ---- advance the move counter on row CR: fill 1's from the right ----
        ones = np.where(out[CR] == 1)[0]
        col = 63 if len(ones) == 0 else int(ones.min()) - 1
        if 0 <= col < W:
            out[CR, col] = 1

    # ---- action 5: switch the selected cross (best effort) ----
    elif action == 5 and len(zeros) > 0:
        cr, cc = int(zeros[0][0]), int(zeros[0][1])
        C = arm_color(cr, cc)
        if C is not None:
            out[cr, cc] = C
        for r in range(1, H - 1):
            done = False
            for c in range(1, W - 1):
                if (r, c) == (cr, cc):
                    continue
                v = out[r, c]
                if v != BG and v != 0 and out[r - 1, c] == v and out[r + 1, c] == v \
                        and out[r, c - 1] == v and out[r, c + 1] == v:
                    out[r, c] = 0
                    done = True
                    break
            if done:
                break

    return out
